import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as d,c as h,d as r,a,b as n,e as c}from"./app-02133217.js";const o={},t=a("h1",{id:"线性表总结",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#线性表总结","aria-hidden":"true"},"#"),n(" 线性表总结")],-1),s=c('<h2 id="顺序表和链表的比较" tabindex="-1"><a class="header-anchor" href="#顺序表和链表的比较" aria-hidden="true">#</a> 顺序表和链表的比较</h2><h3 id="存取方式" tabindex="-1"><a class="header-anchor" href="#存取方式" aria-hidden="true">#</a> 存取方式</h3><ul><li>顺序表支持顺序存取和随机存取；</li><li>链表只能从表头顺序存取元素，支持顺序存取；</li></ul><h3 id="逻辑结构与物理结构" tabindex="-1"><a class="header-anchor" href="#逻辑结构与物理结构" aria-hidden="true">#</a> 逻辑结构与物理结构</h3><ul><li>顺序存储时，逻辑上相邻的元素，对应的物理存储位置也相邻【一定性】。</li><li>链式存储时，逻辑上相邻的元素，对应的物理存储位置不一定相邻【可以相邻，也可以不相邻】。</li><li>链式存储的逻辑关系通过指针链接表示；</li></ul><h3 id="时间复杂度" tabindex="-1"><a class="header-anchor" href="#时间复杂度" aria-hidden="true">#</a> 时间复杂度</h3><h4 id="按值查找" tabindex="-1"><a class="header-anchor" href="#按值查找" aria-hidden="true">#</a> 按值查找</h4><ul><li>顺序表无序的情况下，顺序表和链表的时间复杂度均为O(n)</li><li>顺序表有序的情况下，顺序表的时间复杂度为O(log<sub>2</sub>n)，链表的时间复杂度为O(n)；</li></ul><p><strong>注意：O(log<sub>2</sub>n) &lt; O(n)</strong></p><h4 id="按序号查找" tabindex="-1"><a class="header-anchor" href="#按序号查找" aria-hidden="true">#</a> 按序号查找</h4><ul><li>顺序表支持随机访问，时间复杂度为O(1)；</li><li>顺序表不支持随机访问，时间复杂度为O(n)；</li></ul><h4 id="插入、删除" tabindex="-1"><a class="header-anchor" href="#插入、删除" aria-hidden="true">#</a> 插入、删除</h4><ul><li>顺序表平均需要移动半个表长的元素；</li><li>链表只需要修改相应结点的指针域，不需要移动元素；</li><li>链表结点除了数据域，还有指针域，在存储空间上比顺序存储需要更大的存储空间，付出更大的存储代价，存储密度不够大</li></ul><h3 id="空间分配" tabindex="-1"><a class="header-anchor" href="#空间分配" aria-hidden="true">#</a> 空间分配</h3><h4 id="顺序存储" tabindex="-1"><a class="header-anchor" href="#顺序存储" aria-hidden="true">#</a> 顺序存储</h4><h5 id="静态分配" tabindex="-1"><a class="header-anchor" href="#静态分配" aria-hidden="true">#</a> 静态分配</h5><ul><li>需要预先分配足够大的存储空间；</li><li>空间装满后不能扩充，存储新元素将出现<code>内存溢出</code>；</li><li>存储空间过大，顺序表后部闲置空间过多，造成<code>内部碎片</code></li><li>存储空间过小，会造成<code>内存溢出</code></li></ul><h5 id="动态分配" tabindex="-1"><a class="header-anchor" href="#动态分配" aria-hidden="true">#</a> 动态分配</h5><ul><li>动态分配能够扩充存储空间，但需要移动大量元素，操作效率降低</li><li>内存中没有更大块的连续存储空间，将会导致空间分配失败；</li></ul><h4 id="链式存储" tabindex="-1"><a class="header-anchor" href="#链式存储" aria-hidden="true">#</a> 链式存储</h4><ul><li>链式存储的结点空间只在需要的时候申请分配</li><li>只要内存由空间就可以分配，操作灵活、高效</li></ul><h2 id="存储结构的选取" tabindex="-1"><a class="header-anchor" href="#存储结构的选取" aria-hidden="true">#</a> 存储结构的选取</h2><h3 id="基于存储的考虑" tabindex="-1"><a class="header-anchor" href="#基于存储的考虑" aria-hidden="true">#</a> 基于存储的考虑</h3><ul><li>对线性表的长度和存储规模难以估计时，不宜采用顺序表存储</li><li>链表不用事先估计存储规模，但存储密度较低</li><li>链式存储结构的存储密度小于1，不要求连续的存储空间</li></ul><h3 id="基于运算的考虑" tabindex="-1"><a class="header-anchor" href="#基于运算的考虑" aria-hidden="true">#</a> 基于运算的考虑</h3><ul><li>顺序表支持随机存取，按序号查找顺序表的时间复杂度为O(1)；</li><li>链表不支持随机存取，按序号查找链表的时间复杂度为O(n);</li><li>顺序表的插入、删除操作，平均需要移动表中一半的元素，当表的数据量较大时，这种情况需要重点考虑的。</li><li>链表的插入、删除操作，也是需要找插入位置（前驱结点、后继结点），主要的操作还是比较操作，相对较好；</li></ul><h3 id="基于环境的考虑" tabindex="-1"><a class="header-anchor" href="#基于环境的考虑" aria-hidden="true">#</a> 基于环境的考虑</h3><ul><li>顺序表容易实现，任何高级语言中都有数组类型；</li><li>链表操作是基于指针的，指针移动，相对复杂；</li></ul><p>综上比较</p><ul><li>通常比较稳定的线性表选择顺序存储；</li><li>频繁进行插入、删除操作的线性表，应该选择链式存储，动态性较强</li></ul><h2 id="知识补充" tabindex="-1"><a class="header-anchor" href="#知识补充" aria-hidden="true">#</a> 知识补充</h2><ul><li>无论是链表的插入还是删除操作，必须保证不断链【重要】</li><li>顺序存储结构可以随机存取也能顺序存取，链式结构只能进行顺序存取</li><li>顺序存储方式同样适合图和树的存储，例如：满二叉树的顺序存储</li><li>队列需要在表头删除元素，在表尾插入元素【先进先出】，采用带尾指针的循环单链表比较方便</li><li>数组排序最少时间复杂度为O(nlog<sub>2</sub>n)【重要】</li><li>静态链表中的指针称为<code>游标</code>，指示下一个元素在数组中的<code>下标</code></li><li>静态链表用数组表示，需要预先分配较大的连续空间，同时具有一般链表的特点（插入、删除元素不需要移动元素）</li></ul><h3 id="单链表设置头结点" tabindex="-1"><a class="header-anchor" href="#单链表设置头结点" aria-hidden="true">#</a> 单链表设置头结点</h3><p>目的</p><blockquote><p>主要是方便运算。</p></blockquote><p>好处</p><ul><li>有头结点后，插入、删除数据元素的算法统一起来了，不需要判断是否在第一个元素之前插入或者删除第一个元素了。</li><li>不论链表是否为空，头指针是指向头结点的<code>非空指针</code>，链表的头指针不变，因此空链表和非空链表的处理也就统一起来了。</li></ul>',37);function u(b,f){const e=l("Mermaid");return d(),h("div",null,[t,r(e,{id:"mermaid-3",code:""}),s])}const p=i(o,[["render",u],["__file","summary.html.vue"]]);export{p as default};
